end

local function __dec(d, k)
  local kl = #k
  for l = 3, 1, -1 do
    for i = 1, #d do
      local off = ((i-1) * 7 + l * 13) % kl
      d[i] = __xor(d[i], k[(off + l * 3) % kl + 1])
    end
  end
  return d
end

local function __str(b)
  local c={}
  for i=1,#b,180 do
    local e=math.min(i+179,#b)
    local a={}
    for j=i,e do a[#a+1]=b[j] end
    c[#c+1]=string.char(table.unpack(a))
  end
  return table.concat(c)
end

